pub fn schema() -> meerkat_machine_schema::MachineSchema {
    meerkat_machine_schema::flow_frame_machine()
}

pub fn kernel() -> GeneratedMachineKernel {
    GeneratedMachineKernel::new(schema())
}

pub fn initial_state() -> State {
    let legacy = kernel()
        .initial_state()
        .expect("compat machine initial state must derive from schema init");
    state_from_kernel(legacy).expect("compat machine initial state must decode to typed state")
}

pub fn transition(
    state: &State,
    input: Input,
    _context: &impl Context,
) -> Result<Outcome, TransitionError> {
    let trigger = TriggerDiscriminant::Input(input.kind());
    let legacy_state = state_to_kernel(state);
    let legacy_input = input_to_kernel(&input);
    let legacy = kernel()
        .transition(&legacy_state, &legacy_input)
        .map_err(|error| map_legacy_error(error, state.phase.clone(), trigger.clone()))?;
    outcome_from_kernel(legacy).map_err(TransitionError::Kernel)
}

